mapper.select:
select
from school_class sc join grade g on sc.grade_id = g.grade_id left join teacher t on sc.head_teacher_id = t.teacher_id
order by sc.class_id limit #{pageSize} offset #{offset}

select count(*)
from school_class
where class_name = #{className}

    and class_id != #{classId}

select count(*)
from student
where class_id = #{classId}

select count(*)
from class_course_teacher
where class_id = #{classId}

mapper.update:
update school_class
set class_name = #{className},
    grade_id = #{gradeId},
    head_teacher_id = #{headTeacherId}
where class_id = #{classId}
